// Função para converter volume em número (litros)
function volumeParaNumero(volume) {
  const v = (volume || '').toLowerCase().replace(/\s+/g, '').replace(',', '.');

  // Remove 'l' ou 'ml' e converte para número em litros
  let num = parseFloat(v.replace(/[a-z]/g, ''));

  if (v.includes('ml')) {
    num = num / 1000; // converte ml para litros
  }

  return isNaN(num) ? 0 : num;
}

// Função para mapear volume numérico para embalagem
function numeroParaEmbalagem(volumeLitros) {
  // Define os volumes padrão e suas embalagens
  const padroes = [
    { volume: 0.9, embalagem: 'LITRO' },
    { volume: 3.6, embalagem: 'GALÃO' },
    { volume: 18, embalagem: 'LATA' },
    { volume: 16, embalagem: 'LATA' }
  ];

  // Encontra o volume mais próximo
  let maisProximo = padroes[0];
  let menorDiferenca = Math.abs(volumeLitros - padroes[0].volume);

  for (const padrao of padroes) {
    const diferenca = Math.abs(volumeLitros - padrao.volume);
    if (diferenca < menorDiferenca) {
      menorDiferenca = diferenca;
      maisProximo = padrao;
    }
  }

  return maisProximo.embalagem;
}

// Pega o volume e acabamento que o cliente pediu
const volumePedido = items[0].json.volume;
const acabamentoEsperado = (items[0].json.acabamento || '').toLowerCase().trim();

