// === 1) Referência e normalização ===
const ref = items[0]?.json || {};
const acabamentoCliente = ref.acabamento || '';
const linhaCliente = ref.Linha || ''; // ✅ ADICIONADO: captura a Linha

function normaliza(txt) {
  return (txt || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

// Equivalências (bidirecional simples)
const equivalencias = {
  // acetinado / sedoso
  acetinado: ['acetinado', 'acetinada', 'seda', 'sedoso'],
  acetinada: ['acetinado', 'acetinada', 'seda', 'sedoso'],
  seda:      ['acetinado', 'acetinada', 'seda', 'sedoso'],
  sedoso:    ['acetinado', 'acetinada', 'seda', 'sedoso'],

  // fosco
  fosco: ['fosco', 'matte'],
  matte: ['fosco', 'matte'],

  // brilhante
  brilhante: ['brilho', 'brilhante'],
  brilho:    ['brilho', 'brilhante'],
  semibrilho: ['diamante'],

  // clássica
  classica:    ['classica', 'tradicional'],
  tradicional: ['classica', 'tradicional'],
};

const acbClienteNorm = normaliza(acabamentoCliente);
const palavrasAceitas = acbClienteNorm
  ? (equivalencias[acbClienteNorm] || [acbClienteNorm])
  : null; // null => não filtra por acabamento quando cliente não informou

// === 2) Filtra itens válidos (descarta item 0 e quem não tem chaveCitel) ===
let candidatos = items.slice(1).filter(i => !!i?.json?.chaveCitel);

// === 3) Aplica filtro por acabamento (somente se cliente informou algo) ===
if (palavrasAceitas) {
  candidatos = candidatos.filter(i => {
    const acbItem = normaliza(i.json.acabamento);
    if (!acbItem) return false;
    return palavrasAceitas.some(word =>
      acbItem.includes(word) || word.includes(acbItem)
    );
  });
}

// ✅ ADICIONADO: Se não encontrou nada pelo acabamento, tenta pela Linha
if (candidatos.length === 0 && linhaCliente) {
  const linhaNorm = normaliza(linhaCliente);
  candidatos = items.slice(1).filter(i => {
    if (!i?.json?.chaveCitel) return false;
    const acbItem = normaliza(i.json.acabamento);
    // Verifica se o acabamento contém a linha
    return acbItem.includes(linhaNorm);
  });
}

// === 4) Deduplica por chaveCitel (evita POST duplicado) ===
const vistos = new Set();
candidatos = candidatos.filter(i => {
  const k = String(i.json.chaveCitel);
  if (vistos.has(k)) return false;
  vistos.add(k);
