  }
}));

// saída: [{ json: { mensagem } }]

// === UTILS (funções auxiliares) ===
const up = s => String(s || '')
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .toUpperCase().trim();

function volumeByEmbalagem(e = '') {
  const v = up(e);
  if (v.includes('LATA')) return '18 L';
  if (v.includes('GALAO')) return '3,6 L';
  if (v.includes('LITRO') || v === 'L') return '0,9 L';
  return '';
}

function embalagemEsperada(volume) {
  const v = String(volume || '').replace(',', '.').replace(/\s+/g,'').toUpperCase();
  if (v.startsWith('18') || v.startsWith('16'))  return 'LATA';
  if (v.startsWith('3.6')) return 'GALAO';
  if (v.startsWith('0.9') || v.startsWith('0.5') || v.includes('900ML')) return 'LITRO';
  return '';
}

function formatarMensagemProduto(produto, volRaw, aviso = '') {
  const volStr = volumeByEmbalagem(produto.embalagem) || produto.volume || volRaw || '';
  const desc = `${produto.sigla} ${produto.cor} ${produto.acabamento} ${produto.embalagem} ${volStr}`.replace(/\s+/g,' ').trim();
  const precoBRL = produto.preco.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  const disponibilidade = produto.estoque > 0 ? '✅ Disponível em estoque' : '⚠️ Sob consulta';
  let mensagem = `• ${desc}\n💰 Preço: ${precoBRL}\n📦 ${disponibilidade}`;
  if (aviso) mensagem += `\n\n${aviso}`;
  else mensagem += `\n\nPosso seguir com esse item?`;
  return mensagem;
}
// === FIM UTILS ===


// 1) Pega metadados (último item do array)
const meta = items[items.length - 1]?.json || {};
const SIGLA  = up(meta.sigla);
const SUPERF = up(meta.superficie || meta['superfície']);
const ACABPD = up(meta.acabamento || meta.acabamentoPedido);
const VOLRAW = meta.volume || '';
const CODCOR = meta.codigoCor || '';

// 💥 CAPTURA DE LINHA (com limpeza completa)
let LINHA = up(
  meta.linha ||
  meta.Linha ||
  meta.linhaProduto ||
  meta['linha produto'] ||
  ''
);

// remove ruídos que NÃO são linha de produto
LINHA = LINHA
  .replace(/(SUVINIL|TINTA|ACRILICO|ACRILICA|PAREDE|INTERNA|EXTERNA|PREMIUM)/g, ' ')
  .replace(/\s\s+/g, ' ')
  .trim();

if (!LINHA || LINHA.length < 3) LINHA = '';


// 2) Junta descrições + preços
const descs  = items.filter(i => Array.isArray(i.json?.hashesMd5)).map(i => i.json);
const prices = items.filter(i => typeof i.json?.hashMd5 === 'string').map(i => i.json);
const priceByHash = Object.fromEntries(prices.map(p => [p.hashMd5, p]));

let produtos = descs.map(d => {
  const h = d.hashesMd5?.[0];
  const p = priceByHash[h];
  if (!p) return null;
  return {
    sigla: d.sigla,
    cor: d.cor,
    acabamento: d.acabamento,
    embalagem: d.embalagem,
    volume: d.volume,
    preco: Number(p.preco1 || 0),
