}).filter(Boolean);


// 3) Filtra por embalagem coerente
const embOK = embalagemEsperada(VOLRAW);
if (embOK) produtos = produtos.filter(p => up(p.embalagem) === embOK);


// 💥 4) SE TEM LINHA ESPECÍFICA, PRIORIZA ELA ACIMA DE TUDO
if (LINHA) {
  const produtosLinha = produtos.filter(p => {
    const acab = up(p.acabamento);
    // verifica se contém a linha inteira OU todas as palavras da linha
    const words = LINHA.split(' ').filter(Boolean);
    return acab.includes(LINHA) || (words.length > 1 && words.every(w => acab.includes(w)));
  });

  if (produtosLinha.length > 0) {
    // tem produtos na linha pedida — escolhe o melhor (com preço e estoque)
    const comPreco = produtosLinha.filter(p => p.preco > 0);

    if (comPreco.length > 0) {
      // ordena por estoque (maior primeiro), depois preço (menor)
      comPreco.sort((a, b) => {
        if (b.estoque !== a.estoque) return b.estoque - a.estoque;
        return a.preco - b.preco;
      });

      const escolhido = comPreco[0];
      return [{ json: { mensagem: formatarMensagemProduto(escolhido, VOLRAW) } }];
    } else {
      // linha existe mas sem preço disponível
      return [{
        json: { mensagem: `Encontrei a linha **${meta.Linha || meta.linha}** mas está sem preço disponível no momento.\nDeseja que um vendedor verifique?` }
      }];
