function scoreAcabamentoFallback(acabamento) {
  const acab = up(acabamento);
  if (ACABPD.includes('ACET') && acab.includes('ACET')) return 500;
  if (ACABPD.includes('FOSCO') && acab.includes('FOSCO')) return 500;
  if (ACABPD.includes('BRILHO') && acab.includes('BRILHO')) return 500;
  if (ACABPD.includes('SEMI') && acab.includes('SEMI')) return 500;
  return 100;
}

produtos.sort((a, b) => {
  const scoreA = scoreAcabamentoFallback(a.acabamento);
  const scoreB = scoreAcabamentoFallback(b.acabamento);
  if (scoreB !== scoreA) return scoreB - scoreA;
  if (b.estoque !== a.estoque) return b.estoque - a.estoque;
  return a.preco - b.preco;
});

const escolhidoFallback = produtos[0];
const aviso = '⚠️ Produto sugerido baseado em disponibilidade e melhor preço.';
return [{ json: { mensagem: formatarMensagemProduto(escolhidoFallback, VOLRAW, aviso) } }];

